#include <bits/stdc++.h>
using namespace std;
int n,k,f[300005],ans;
int fa(int x)
{
    if(f[x]==x) return x;
    else return f[x]=fa(f[x]);
}
void fun(int x,int y)
{
    int fx=fa(x),fy=fa(y);
    f[fx]=fy;
}
int main()
{
    cin>>n>>k;
    for(int i=1;i<=3*n;i++) f[i]=i;
    for(int i=1;i<=k;i++)
    {
        int t,x,y;
        cin>>t>>x>>y;
        if(x>n||y>n)
        {
            ans++;
            continue;
        }
        if(t==1)
        {
            if(fa(x+n)==fa(y)||fa(x+2*n)==fa(y)) ans++;
            else
            {
                fun(x,y);
                fun(x+n,y+n);
                fun(x+2*n,y+2*n);
            }
        }
        else
        {
            if(fa(x)==fa(y)||fa(x+2*n)==fa(y)) ans++;
            else
            {
                fun(x,y+2*n);
                fun(x+n,y);
                fun(x+2*n,y+n);
            }
        }
    }
    cout<<ans;
    return 0;
}
